export interface ResourceData {
  time: string;
  cpu: number;
  ram: number;
}

export interface ActivityData {
  date: string;
  count: number;
}

export interface HistoryItem {
  id: string;
  name: string;
  timestamp: string;
  status: 'online' | 'offline';
}

export interface SystemStats {
  cpu: number;
  ram: number;
  storage: number;
  network: number;
}

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { MonitorDashboard } from './components/MonitorDashboard';
import { SystemStats, ResourceData, HistoryItem } from './types';

const App: React.FC = () => {
  const [stats, setStats] = useState<SystemStats>({
    cpu: 28,
    ram: 4,
    storage: 65,
    network: 203
  });

  const [resourceHistory, setResourceHistory] = useState<ResourceData[]>([]);
  const [historyItems, setHistoryItems] = useState<HistoryItem[]>([
    { id: '1', name: 'NAFIZA AZZAHRA SABRINA', timestamp: '2026-02-09', status: 'online' },
    { id: '2', name: 'KENZO DIKI ABISATYA NURROHKIM', timestamp: '2026-02-09', status: 'online' },
    { id: '3', name: 'KENAN DIKA ABISATYA NURROHKIM', timestamp: '2026-02-09', status: 'online' },
    { id: '4', name: 'SAFIRA ALMIRA SALMA', timestamp: '2026-02-09', status: 'online' },
    { id: '5', name: 'ANANTA SHAHREEN KHOLIFATUNISA', timestamp: '2026-02-09', status: 'online' },
    { id: '6', name: 'JOANNA IASHA', timestamp: '2026-02-09', status: 'online' },
  ]);

  // Simulate real-time monitoring data
  useEffect(() => {
    const interval = setInterval(() => {
      const now = new Date();
      const timeStr = now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });

      const newCpu = Math.floor(Math.random() * (45 - 15 + 1)) + 15;
      const newRamPerc = Math.floor(Math.random() * (80 - 40 + 1)) + 40;
      const newNetwork = Math.floor(Math.random() * (500 - 50 + 1)) + 50;

      setStats(prev => ({
        ...prev,
        cpu: newCpu,
        network: newNetwork
      }));

      setResourceHistory(prev => {
        const newData = [...prev, { time: timeStr, cpu: newCpu, ram: newRamPerc }];
        return newData.slice(-20); // Keep last 20 data points
      });
    }, 2000);

    return () => clearInterval(interval);
  }, []);

  return (
    <Layout stats={stats}>
      <MonitorDashboard 
        stats={stats} 
        resourceHistory={resourceHistory} 
        historyItems={historyItems}
      />
    </Layout>
  );
};

export default App;

